import "fmt"

type State int

const (
	Idle State = iota
	Running
	Done
)

// next advances the state machine; ok is false when there is no transition.
func next(s State) (State, bool) {
	switch s {
	case Idle:
		return Running, true
	case Running:
		return Done, true
	default:
		return s, false
	}
}

func main() {
	s := Idle
	for {
		ns, ok := next(s)
		if !ok {
			break
		}
		s = ns
	}
	fmt.Println("final state:", s)
}
