func main() {
	const n = 5
	errs := make([]error, n)

	var wg sync.WaitGroup
	for i := 0; i < n; i++ {
		wg.Add(1)
		go func(i int) {
			defer wg.Done()
			errs[i] = work(i) // each goroutine owns its own slot
		}(i)
	}
	wg.Wait()

	if err := errors.Join(errs...); err != nil { // nil entries are ignored
		fmt.Println("some work failed:", err)
	} else {
		fmt.Println("all ok")
	}
}
